      "auto.attr.zl5o34": "تاريخ العمل القصير والشهادات والقيود والطرق المفضلة",
      "auto.text.1000nke": "CrewPortGlobal — اتفاقية خدمة مالك السفينة",
      "auto.text.106vtz0": "تحميل",
      "auto.text.107hffs": "الاتصال والعناوين الشخصية",
      "auto.text.108cyeb": "يحدد ما هو CrewPortGlobal، وما ليس كذلك، وكيف يتم تأطير النموذج التجاري للمرحلة الأولى.",
      "auto.text.109is80": "رسوم الاستقدام المحظورة",
      "auto.text.10a8kh1": "يتم تقديم معلومات المرشح الآمنة لصاحب العمل والتي تمت مراجعتها فقط إلى العميل.",
      "auto.text.10ay9wb": "عرض داخلي محمي. فهو يسرد مسودات القائمة المختصرة الداخلية فقط، وعملياتها المسؤولة، وأعداد المرشحين الآمنة. يتم استبعاد جهات الاتصال وبيانات تعريف المستند.",
      "auto.text.10b1168": "تقوم هذه الحقول بإعداد بيانات الشخص الطبيعي وبيانات الاتصال في حالات الطوارئ للتحقق منها في المستقبل.",
      "auto.text.10b6o36": "إجراءات التعامل مع الشكوى",
      "auto.text.10cbdix": "طلب الطاقم",
      "auto.text.10fxzfd": "وثائق لمراجعة الترخيص",
      "auto.text.10iged5": "موقع الكتروني: https://crewportglobal.com",
      "auto.text.10jyajz": "طلب الوظيفة الشاغرة",
      "auto.text.10kqs13": "خصم رسوم الوصول المتعلقة بالتوظيف من الأجور؛",
      "auto.text.10li0wv": "مرجع الملف الشخصي",
      "auto.text.10mhr2e": "مرشح المفتاح",
      "auto.text.10mx6iy": "أدلة السفينة / الإدارة",
      "auto.text.10n67qa": "القدرة اللغوية المعلنة أو متطلبات الدور القانوني الأخرى.",
      "auto.text.10n9404": "كروبورتجلوبال | خزانة شخصية",
      "auto.text.10njyf7": "يدير المرشحون ملفًا بحريًا منظمًا بالرتبة والخبرة والوثائق والتوافر.",
      "auto.text.10q0c8h": "فرز",
      "auto.text.10q77w2": "في انتظار المراجعة.",
      "auto.text.10qk6do": "يتم فهم أي إشارات لجاهزية المستندات؛",
      "auto.text.10qprnm": "السفن وبيانات السفينة والسياق التشغيلي حيث يعتمد عرض المرشح عليها.",
      "auto.text.10qru14": "التوفر.",
      "auto.text.10uawex": "المجموعات والأدوار",
      "auto.text.10weq5w": "رقم كتاب البحار",
      "auto.text.113magn": "كروبورتجلوبال | مراجعة الوثيقة",
      "auto.text.115hmdm": "تحميل محمي",
      "auto.text.115xsjg": "يمكنك تقديم شكوى بخصوص",
      "auto.text.116jb8z": "يحافظ على مسار التدقيق الموجه نحو الامتثال.",
      "auto.text.117ebo9": "يجب أن تكون معايير المطابقة ذات صلة بالدور، وقانونية ويمكن الدفاع عنها، دون أي تمييز محظور.",
      "auto.text.11ac54b": "لم يتم حفظها بعد",
      "auto.text.11cu7hf": "ملفات تعريف البحارة المعدة فقط",
      "auto.text.11dhnfd": "\"الدفع للحصول على العقد.\"",
      "auto.text.11ehzrp": "التزامات السداد لا تزال متأخرة؛",
      "auto.text.11fsgah": "كل العمل",
      "auto.text.11kdntf": "كيف يتم استخدام البيانات",
      "auto.text.11klrsp": "المصطلحات الأساسية",
      "auto.text.11l94wb": "تسجيل الخروج",
      "auto.text.11n9kj4": "تحميل البرامج الضارة أو الملفات الضارة.",
      "auto.text.11nx308": "شهادات الناقلات.",
      "auto.text.11qp0uv": "الموافقة على التحديد",
      "auto.text.11s0ggy": "مركز الثقة",
      "auto.text.11uk0xx": "يجوز لـ CrewPortGlobal تعليق عملية الإعداد أو تقييد الخدمات أو طلب المستندات الداعمة أو رفض الخدمة في الحالات التالية:",
      "auto.text.11uw6tj": "مراجعة المرشحين من خلال المراجعة البشرية",
      "auto.text.11vtnm4": "تسجيل الدخول / التسجيل",
      "auto.text.11xpj1w": "وضع علامة على الوثائق كما تم التحقق منها.",
      "auto.text.11yg0us": "ينبغي تأكيد القانون الحاكم ومنتدى حل النزاعات أثناء المراجعة القانونية.",
      "auto.text.1213sic": "يجب أن يقتصر الوصول إلى البيانات الحساسة على سير العمل والموظفين المعتمدين؛",
      "auto.text.122f535": "مجموعة من السفن والطرق وسياق الشركة؛",
      "auto.text.122i1nf": "جواز السفر / الهوية",
      "auto.text.12489v": "تظهر الوظائف الشاغرة العامة فقط عندما تكون بيانات الوظائف الشاغرة التي تمت مراجعتها جاهزة.",
      "auto.text.124mz7z": "يدعم CrewPortGlobal إدارة الملفات الشخصية المنظمة ومطابقة سير العمل، ولكن يتم اتخاذ قرارات التوظيف النهائية من قبل مالكي السفن أو أصحاب العمل أو مشغلي السفن أو مديري السفن أو أطراف التوظيف المعتمدة.",
      "auto.text.125e7se": "نطاق المشروع",
      "auto.text.125fn4y": "التحقق من البطاقة",
      "auto.text.12azs7p": "تغيير النماذج المحددة",
      "auto.text.12b1ev": "يمكن لمستخدمي الأعمال تقديم شكاوى متعلقة بالخدمة أو الامتثال أو الفواتير أو سوء السلوك أو الرسوم من خلال قنوات الشكاوى المنشورة لدى CrewPortGlobal.",
      "auto.text.12co4rw": "قد يدفع مالكو السفن ومشغلو السفن ومديرو السفن وأصحاب العمل البحري مقابل دعم سير العمل ودعم البحث عن المرشحين ومراجعة جاهزية المستندات والخدمات ذات الصلة.",
      "auto.text.12gmgte": "CrewPortGlobal — اتفاقية مرشح البحارة",
      "auto.text.12gnpm4": "جاهزية الوثيقة",
      "auto.text.12gxers": "البيانات التعريفية الفنية اللازمة للأمن وتشغيل الخدمة.",
      "auto.text.12knp7n": "الراتب",
      "auto.text.12l25vi": "التحقق من السفينة يعتمد على المخاطر. وقد تكون خفيفة الوزن بالنسبة لسير العمل منخفض المخاطر وأكثر تفصيلاً عند ظهور أسئلة تتعلق بالملكية أو الإدارة أو العقوبات أو الشرعية.",
      "auto.text.12l382v": "ترتيبات التأمين والرعاية الاجتماعية.",
      "auto.text.12mubvb": "الآن",
      "auto.text.12nrlr5": "الدورات التدريبية",
      "auto.text.12q3vb2": "أذونات فعالة",
