      "auto.text.14vmiwx": "كين المحمول",
      "auto.text.14xeg86": "يطلب المرشح إلغاء التنشيط.",
      "auto.text.14zz1t6": "أدلة أخرى",
      "auto.text.151oono": "إدارة الهوية.",
      "auto.text.154fb2k": "الشروط",
      "auto.text.1574h9r": "معهد COC",
      "auto.text.1580so2": "تخفيض السعر الكنسي",
      "auto.text.15929j3": "يمنحك مسارًا واضحًا لإنشاء ملف تعريف وإعداد المستندات.",
      "auto.text.15dw1m8": "تجربة نوع السفينة؛",
      "auto.text.15e1ptb": "ماذا يعني هذا",
      "auto.text.15gt5d6": "محسوبة من حالة البيانات الحالية.",
      "auto.text.15heuae": "\"ادفع مقابل تقديمك لمالك السفينة.\"",
      "auto.text.15hyoxo": "عندما تقوم CrewPortGlobal بتقديم فرصة مرشح أو تنظيمها أو هيكلتها أو دعمها ماديًا، يجب على مالك السفينة أو العميل التجاري عدم التحايل عمدًا على المنصة بسوء نية لتجنب رسوم B2B المتفق عليها أو الشروط التجارية.",
      "auto.text.15lrxha": "تقديم معلومات مضللة أو غير كاملة أو خاطئة؛",
      "auto.text.15m8swd": "شهادة إدارة السلامة",
      "auto.text.15n54cn": "تاريخ الميلاد",
      "auto.text.15qa7om": "نموذج العمل",
      "auto.text.15qleue": "مراجعة بشرية",
