      "auto.text.165akxr": "نفس الجنسية",
      "auto.text.167hejv": "مرفوض.",
      "auto.text.167ooyj": "يتم منح الوصول من خلال عضوية المجموعة التشغيلية المعتمدة.",
      "auto.text.167qfde": "هاتف الاتصال في حالات الطوارئ",
      "auto.text.167zdwu": "تاريخ العقد ومدى توفره؛",
      "auto.text.168gr5l": "CrewPortGlobal — سياسة عدم وجود رسوم توظيف | CrewPortGlobal",
      "auto.text.168q8mw": "يحافظ CrewPortGlobal على شرح العملية مضغوطًا: التسجيل، والبيانات المنظمة، والتحقق، والمطابقة، والعرض التقديمي، والركوب، وأدلة الفواتير، وتكرار الرحلة.",
      "auto.text.16afg92": "ويمكن اتخاذ تدابير وقائية مؤقتة عند الحاجة.",
      "auto.text.16c3b7": "يجب تأكيد القانون الحاكم وآلية حل النزاعات وأحكام الاختصاص القضائي لهذه الاتفاقية أثناء المراجعة القانونية الرسمية قبل الاستخدام النهائي للإنتاج.",
      "auto.text.16f42vl": "تقديم الخدمة",
      "auto.text.16fb7ko": "الاسم الأول",
      "auto.text.16fmna1": "الترجمة الآلية من Google هي موفر الترجمة الافتراضي. تظل النسخة الإنجليزية هي المعتمدة فيما يتعلق بالخدمة والترجمة القانونية والتشغيلية.",
      "auto.text.16h88tr": "أنواع السفن المفضلة/المقبولة",
      "auto.text.16j6x9": "1. حالة المنصة والوضع التنظيمي",
      "auto.text.16mvbwc": "سيقدم المرشح معلومات دقيقة وحديثة وصادقة.",
      "auto.text.16rfere": "لا تقدم المنصة نفسها على أنها وكالة توظيف مرخصة أو وكالة توظيف البحارة ما لم يتم تأكيد الموافقات المطلوبة.",
      "auto.text.16rxx09": "لا يقيد هذا البند التوظيف المباشر القانوني أو المشاركة في حالة عدم وجود التزام تجاري قابل للتطبيق تجاه CrewPortGlobal.",
      "auto.text.16us7mj": "اللغة",
      "auto.text.16vth7a": "البريد الإلكتروني للملف الشخصي",
      "auto.text.16zhjgm": "التوفر العام الحالي",
      "auto.text.170baal": "مجلس الشغور العام",
      "auto.text.170o7hf": "اكتمال الملف الشخصي مرئي قبل الحفظ",
      "auto.text.171lv90": "مالك",
      "auto.text.17242z8": "تؤكد أدلة الصعود أن البحار المختار قد انضم إلى السفينة.",
      "auto.text.173v1lk": "CrewPortGlobal لا يضمن التوظيف أو التنسيب.",
      "auto.text.174diuu": "المستقبل",
      "auto.text.175ezrv": "سير العمل، وسجلات الاتصالات والشكاوى؛",
      "auto.text.175mc3x": "توثيق البيانات التعريفية وحالة المراجعة",
      "auto.text.176kikp": "يستخدم CrewPortGlobal ضوابط التحقق للحد من الاحتيال وانتحال الشخصية والتعرض للعقوبات والوصول غير المصرح به إلى بيانات المرشح ومطالبات السفن المضللة وإساءة استخدام سير العمل.",
      "auto.text.17a3hk5": "الموافقة على الكتالوج",
      "auto.text.17bx9vq": "مراجعة المرشح",
      "auto.text.17cdb1t": "أدرك أن CrewPortGlobal لا تفرض رسوم توظيف البحارة أو تعيينهم أو توظيفهم.",
      "auto.text.17fvk9r": "تشغيل المقارنة",
      "auto.text.17gruq0": "مشغل الدعم",
      "auto.text.17iu1lr": "البيانات التي قد نقوم بمعالجتها",
