      "auto.text.17l4amv": "توكيل",
      "auto.text.17memme": "7. نتائج المراجعة",
      "auto.text.17mjeq9": "CrewPortGlobal / GTC INFORMATION TECHNOLOGY منطقة حرة - ذ.م.م",
      "auto.text.17nl30i": "شهادة الكفاءة",
      "auto.text.17obutc": "تاريخ ميلاد كين",
      "auto.text.17oib6d": "لا تفرض CrewPortGlobal رسوم توظيف البحارة أو تعيينهم أو توظيفهم.",
      "auto.text.17q4nd4": "التدقيق",
      "auto.text.17q9kbf": "المسؤول 2",
      "auto.text.17t2hgt": "عنوان القربى",
      "auto.text.17u3oau": "الأدوار النشطة",
      "auto.text.17wir4c": "نوع COC",
      "auto.text.17wmwhi": "وظيفة شاغرة",
      "auto.text.17zcjhi": "بيانات كاملة",
      "auto.text.180960e": "المسؤول 1",
      "auto.text.183jmlr": "تلخيص محتوى الملف الشخصي؛",
      "auto.text.184bpvp": "اللغة الإنجليزية هي لغة المنصة الرسمية. لغات الواجهة الأخرى هي توطين الآلة لتوفير الراحة ويتم حفظها في هذا المتصفح.",
      "auto.text.184wra4": "حفظ والتحقق من جاهزية الطلب",
      "auto.text.1871x51": "GTC_USER_ID، إذا كان متاحًا.",
      "auto.text.188p784": "قم بمراجعة النص القانوني ونص الموافقة والثقة المترجم آليًا قبل أن يتم التعامل معه على أنه معتمد من قبل الإنسان.",
      "auto.text.189v4y1": "التعاريف",
      "auto.text.18bs7jf": "يجب على المرشح الإبلاغ عن أي طلب للدفع يبدو أنه مرتبط بالحصول على وظيفة أو عقد أو قائمة مختصرة أو فرصة عمل.",
      "auto.text.18e89ju": "عرض أسطول بحر الشمال",
      "auto.text.18h7i89": "GTC_USER_ID",
      "auto.text.18hk4ah": "استخدم حسابًا واحدًا للاستمرار كبحار أو كممثل لصاحب العمل.",
      "auto.text.18i25tc": "أنا مالك السفينة",
      "auto.text.18ju2xo": "يجوز لشركة CrewPortGlobal تحديث هذه الاتفاقية مع تطور النظام الأساسي أو تغير المتطلبات القانونية أو إضافة خدمات جديدة.",
      "auto.text.18k24qd": "كروبورتجلوبال | فريق",
      "auto.text.18m4f0m": "يجب على المرشح التحقق من:",
      "auto.text.18o4c7r": "جواز السفر.",
      "auto.text.18orewg": "قم بإرفاق المستندات التي تثبت سياق الشركة وحقك في التصرف من أجل طلب جانب المشتري. لم يتم تحميل الملفات على الخادم بعد؛ يتم حفظ البيانات التعريفية محليًا حتى يتم تنفيذ التخزين الخلفي.",
      "auto.text.18p8arf": "في انتظار مراجعة_الإنسان",
      "auto.text.18smdxt": "الموقع الحالي.",
      "auto.text.18t722e": "جاهزية الملف الشخصي",
      "auto.text.18t8gpo": "قد تدعم CrewPortGlobal واحدًا أو أكثر من الأنشطة التالية:",
      "auto.text.18trxg8": "يجب على المرشح حماية بيانات اعتماد الحساب ويجب عليه إخطار CrewPortGlobal في حالة الاشتباه في إساءة استخدام الحساب.",
      "auto.text.18wdvjj": "تخزين سجل سير العمل وسجلات الامتثال.",
      "auto.text.18xphum": "اختر نماذج التفويض",
      "auto.text.18xx3xi": "شهادات الكفاءة والتصديقات وسجلات التدريب؛",
      "auto.text.18zqxar": "ما تساعد فيه المعاينة الحالية بالفعل",
      "auto.text.192krud": "كروبورتجلوبال | طلب مقارنة العرض",
      "auto.text.193fglh": "تم التحقق منها",
      "auto.text.195joue": "يقوم CrewPortGlobal أولاً بتأكيد حساب الشخص والخدمة، ثم يجمع البطاقات المناسبة لمسار العمل ولا يمنح التفويض إلا بعد مراجعة الأدلة.",
      "auto.text.1963u7n": "الهندية",
      "auto.text.19apixc": "اختر نماذج التفويض.",
      "auto.text.19c95gb": "يجوز للمرشح أن يطلب تصحيح ملخصات أو بيانات الملف الشخصي غير الدقيقة.",
      "auto.text.19dsq3o": "نشاط التوظيف الاحتيالي؛",
      "auto.text.19eqmxi": "مراجعة الهدف",
      "auto.text.19eqtfp": "حالة المستند غير صحيحة.",
      "auto.text.19fngoi": "ليس عليك أن تدفع لـ CrewPortGlobal للنظر في فرص الطاقم من خلال المنصة.",
      "auto.text.19fs862": "بلد إصدار COC",
      "auto.text.19fsf45": "تم إرسال الإقرار.",
      "auto.text.19hp4vb": "اتفاق",
      "auto.text.19ko2y2": "العودة إلى الوظائف الشاغرة",
      "auto.text.19kqlwa": "فتح مساحة عمل القائمة المختصرة",
      "auto.text.19ojqyb": "قد تطلب CrewPortGlobal من مستخدمي الأعمال إكمال مراجعة \"اعرف عملك\"، أو التحقق من هوية الممثلين المعتمدين، أو التحقق من الملكية، أو فحص العقوبات، أو فحص الأطراف المحظورة، أو سياق مصدر الأموال، أو أي مراجعة أخرى للامتثال قبل أو أثناء تقديم الخدمة.",
      "auto.text.19owcd3": "مدينة التسجيل",
      "auto.text.19qw9x1": "تسلسل التسجيل",
      "auto.text.19r7moc": "انتهاء هوية البحارة",
      "auto.text.19rc6t4": "قد يشكل الاستمرار في استخدام المنصة بعد تاريخ سريان الشروط المحدثة قبولاً للاتفاقية المحدثة، ما لم يتطلب القانون المعمول به عملية مختلفة.",
      "auto.text.19rqrxf": "قد تستخدم CrewPortGlobal البيانات المنظمة والمراجعة البشرية والأدوات المدعومة بالذكاء الاصطناعي لمقارنة ملفات تعريف المرشحين مع طلبات الطاقم.",
      "auto.text.19t7kh0": "يتمتع المرشح بسلطة تحميل المستندات المقدمة.",
      "auto.text.19xxxs0": "المرشح:",
      "auto.text.1a07izb": "ملاحظة المراجعة الأخيرة: -",
      "auto.text.1a0t7l7": "6. عمق المراجعة على أساس المخاطر",
      "auto.text.1a10ik2": "استخدم أحدث رمز مكون من 6 أرقام تم إرساله إلى البريد الإلكتروني لعضو مجموعتك. إذا طلبت رمزًا جديدًا، فتجاهل رسائل البريد الإلكتروني القديمة.",
      "auto.text.1a1skrz": "سلسلة جوازات السفر المدنية",
      "auto.text.1a1vogl": "في انتظار مراجعة المالك",
      "auto.text.1a2g3v": "يجوز للمرشح أن يطلب إلغاء تنشيط الملف الشخصي.",
      "auto.text.1a46n2r": "لا يتم تقديم المنصة كوكالة توظيف مرخصة ما لم يتم تأكيد الموافقات المطلوبة أو يتم توفير سير العمل ذي الصلة من خلال شركاء مرخصين.",
      "auto.text.1a5e943": "اليونانية",
      "auto.text.1a6on5f": "عقود الطاقم وطلبات الطاقم التي تم التحقق منها",
      "auto.text.1a8eq48": "كتالوج",
      "auto.text.1a95u96": "مؤشرات اكتمال الوثيقة وجاهزيتها؛",
      "auto.text.1adu274": "الجنس",
      "auto.text.1aeugy": "واضح",
      "auto.text.1aevnvc": "إنشاء الملف الشخصي",
      "auto.text.1ajsqnb": "تفاصيل السفينة",
      "auto.text.1aoexpj": "المستندات التي تم تحميلها.",
