      "auto.text.7wb9at": "مراجعة الامتثال غير كاملة أو غير ناجحة؛",
      "auto.text.7wy4bk": "سجلات الأطفال",
      "auto.text.7xsjuf": "تقديم الطلب",
      "auto.text.7z877l": "بيان عدم وجود رسوم الأساسية",
      "auto.text.811vv6": "مذكرة الوزن الساكن/الحمولة",
      "auto.text.81waop": "قم بإنشاء حساب مشارك في النظام الأساسي الخاص بك.",
      "auto.text.84a0we": "لماذا تستخدمه الشركات",
      "auto.text.84kou0": "للتعامل مع الشكاوى والطلبات القانونية وعمليات الامتثال.",
      "auto.text.862v4c": "معالجة الدفع للخدمات الاختيارية، إن وجدت.",
      "auto.text.87tykb": "الرمز البريدي للتسجيل",
      "auto.text.87wxro": "أنا أوافق",
      "auto.text.89igg1": "قد يأخذ عرض المرشح في الاعتبار صلاحية الشهادة واكتمالها وخبرة السفينة المذكورة.",
      "auto.text.8awmmu": "الدولة",
      "auto.text.8fgosc": "جارٍ تحميل قائمة انتظار عامل التشغيل...",
      "auto.text.8ga8pb": "آخر نوع السفينة",
      "auto.text.8hqamv": "المتطلبات الخاصة بالعميل.",
      "auto.text.8hyu5o": "خزانة الفريق",
      "auto.text.8isrz5": "يجب على مالك السفينة عدم إساءة استخدام البيانات الشخصية للمرشح، أو الاحتفاظ بها لفترة أطول من المبررة، أو الكشف عنها خارج عمليات التوظيف أو الامتثال المشروعة، أو معالجتها للتمييز غير القانوني أو النشاط المحظور.",
      "auto.text.8kacj6": "خط الأساس لتسجيل المرشحين",
      "auto.text.8lkbv2": "فتح التأكيد النهائي",
      "auto.text.8rxgvs": "لحماية المنصة والمستخدمين ومسار التدقيق؛",
      "auto.text.8t0gly": "عند التعطيل:",
      "auto.text.8tyoer": "صباحا",
      "auto.text.8wc6pc": "احتفظ بتفاصيل الشهادة وجواز السفر والمستندات منظمة قبل التقديم.",
      "auto.text.8y6g5c": "انتهاء صلاحية تأشيرة شنغن",
      "auto.text.8ywf8j": "التخصص التربوي",
      "auto.text.93f59p": "تتم مراجعة الأدلة.",
      "auto.text.96b2g0": "معهد تأييد",
      "auto.text.96pm64": "يطلب إرسال الأموال.",
      "auto.text.989tzj": "النموذج التجاري الأساسي لـ CrewPortGlobal هو B2B.",
      "auto.text.9b743l": "يشارك المرشح في عمليات احتيال أو نشاط غير قانوني.",
      "auto.text.9bfa90": "أدرك أن المصادقة والتفويض هما خطوتان منفصلتان ولا يتم منح أي دور أو رؤية البيانات تلقائيًا.",
      "auto.text.9cso0p": "قد تقوم المنصة بجمع المعلومات من خلال نماذج الويب أو حوار الدردشة أو تحميل المستندات أو استبيانات الإعداد أو دعم الاتصالات.",
      "auto.text.9equt9": "يجب أن يقتصر تبادل البيانات على احتياجات الخدمة والامتثال المشروعة؛",
      "auto.text.9et8q5": "مجموعة النشر",
      "auto.text.9f0gzw": "لا يتعين عليك شراء خدمات اختيارية من CrewPortGlobal لإنشاء ملف تعريف أو الظهور في المجموعة المتطابقة أو النظر في طلب الطاقم ذي الصلة.",
      "auto.text.9fktla": "إذا تم تقديم خدمات اختيارية مدفوعة الأجر للبحارة في المستقبل، فيجب تحديد هذه الخدمات بوضوح على أنها اختيارية، ومنفصلة عن الوصول إلى التوظيف وليست شرطًا للنظر فيها أو إدراجها في القائمة المختصرة أو فرصة العمل.",
      "auto.text.9gh086": "لا يمكن ضمان أمان أي نظام بشكل كامل. يجب على المرشح تجنب إرسال معلومات حساسة غير ضرورية عبر القنوات غير المعتمدة.",
      "auto.text.9hopc0": "وينبغي الإبلاغ عن الاتصالات المشبوهة.",
      "auto.text.9hrw4w": "4. مسؤوليات مالك السفينة",
      "auto.text.9ilfrn": "كتاب البحارة",
      "auto.text.9iqdym": "اتفاقية البحارة",
      "auto.text.9lqz42": "المعاينة الحالية",
      "auto.text.9m1ool": "رقم COC",
      "auto.text.9mwxuo": "قد يزداد عمق التحقق عندما:",
      "auto.text.9n61eh": "بطاقة الشخص المادي",
      "auto.text.9q2tqo": "التحكم في توطين الفريق",
      "auto.text.9seph9": "فندق",
      "auto.text.9v5rmw": "يعني ملف التعريف المهني الرقمي الذي تم إنشاؤه للمرشح، بما في ذلك التفاصيل الشخصية والخبرة المهنية والشهادات والتوافر والمستندات وغيرها من المعلومات المقدمة.",
      "auto.text.a0cq84": "مفقود للمراجعة",
      "auto.text.a31ji8": "الجدول الزمني المتوقع",
      "auto.text.a3kq4u": "يجب أن تقتصر المسؤولية الإجمالية لشركة CrewPortGlobal بموجب هذه الاتفاقية على مبلغ رسوم B2B التي يدفعها فعليًا العميل التجاري المعني لفترة الخدمة المتأثرة بشكل مباشر، باستثناء الحالات التي يتطلب فيها القانون غير القابل للاستبعاد معيارًا أعلى.",
      "auto.text.a53qd2": "يساعد مالكي السفن على تنظيم طلبات الطاقم؛",
      "auto.text.a86scz": "البريد الإلكتروني 1",
      "auto.text.a94ot4": "لقب كين",
      "auto.text.a99tzp": "تتبع بيانات تعريف المستند المصنف المصدر. تظل عمليات تحميل الملفات محمية ومنفصلة.",
      "auto.text.ab2tcv": "سياسة الخصوصية",
      "auto.text.absmwr": "منطقة التداول والطريق ونافذة الانضمام المتوقعة وفترة العقد؛",
      "auto.text.ahrdg": "طلبات الطاقم المقدمة من مالكي السفن أو مشغلي السفن أو مديري السفن أو مستخدمي الأعمال المعتمدين؛",
      "auto.text.ai6e1y": "البريد الإلكتروني 2",
      "auto.text.aikko6": "ن.س",
      "auto.text.ajg4vy": "خط الأساس للتحقق من الهوية وعميل الأعمال والسفينة لكلا جانبي سير عمل الطاقم.",
      "auto.text.ak5vdb": "كروبورتجلوبال | اختيار بطاقة التفويض",
      "auto.text.alvayy": "التحقق من السفينة",
      "auto.text.amwd14": "الاسم.",
      "auto.text.ao0gz3": "دعم مراجعة جاهزية المستندات.",
      "auto.text.aojq6l": "الضغط للتحرك على الفور.",
      "auto.text.apc6hd": "انسحاب صاحب العمل من الوظيفة الشاغرة أو العرض.",
      "auto.text.aptu8p": "مدة العقد",
      "auto.text.aqb0i": "حافظ على تحديث بيانات الملف الشخصي.",
      "auto.text.aqkxor": "إنشاء الملف الشخصي",
      "auto.text.aqoi05": "يجب مراجعة هذا القسم من قبل مستشار قانوني قبل النشر النهائي.",
      "auto.text.arx29h": "بطاقة طلب من جهة صاحب العمل",
      "auto.text.aurg4a": "قد تستخدم CrewPortGlobal أدوات الذكاء الاصطناعي من أجل:",
      "auto.text.aurrjr": "الراتب.",
      "auto.text.av5pfw": "سوء سلوك الشريك.",
      "auto.text.avgzna": "معرف طلب الطاقم",
