      "auto.text.bn3fv8": "اسم السفينة الأخير",
      "auto.text.boyus3": "CPG",
      "auto.text.bppu04": "قد تشمل أمثلة السلوك المحظور ما يلي:",
      "auto.text.bqhzjx": "حالة المراجعة: غير متاحة بعد.",
      "auto.text.bqlnpd": "13. البيانات الشخصية",
      "auto.text.bsy10l": "15. حدود المسؤولية",
      "auto.text.btg0jb": "تقوم CrewPortGlobal بجمع البيانات ومعالجتها فقط لأغراض النظام الأساسي والتشغيلي والأمني والامتثال.",
      "auto.text.burj6v": "خدمة الفاتورة",
      "auto.text.bwevbp": "يعني أي رسم أو أجرة أو خصم مفروض على البحار كشرط للحصول على العمل أو التنسيب أو التعيين.",
      "auto.text.bxb127": "المراجع.",
      "auto.text.bxwa35": "الوظائف الشاغرة التي تمت مراجعتها",
      "auto.text.bygjtv": "ملف",
      "auto.text.bzan9q": "طلب أدلة داعمة إضافية؛",
      "auto.text.c2hujn": "يمكن التعامل مع الشكاوى المتعلقة بتغيير رسوم البحارة أو إساءة استخدام المستندات أو الاحتيال أو المخاوف المتعلقة بالعقوبات أو السلوك التعسفي على أنها مسائل ذات أولوية وقد تؤدي إلى مراجعة داخلية فورية.",
      "auto.text.c2obzv": "تم التحقق منها على جانبي سير عمل الطاقم",
      "auto.text.c348uo": "لا تضمن CrewPortGlobal توفر المرشح أو نشره أو صعوده أو إصدار التأشيرة أو الموافقة على العلم أو الموافقة الطبية أو القبول التنظيمي أو أي نتائج توظيف.",
      "auto.text.c54pc7": "بناء أساسيات السيرة الذاتية",
      "auto.text.c5lz4e": "ملكية السفينة أو إدارتها أو سلطة الطاقم عند الاقتضاء.",
      "auto.text.c5utwq": "مخاوف الخصوصية.",
      "auto.text.c7zq7m": "احتياطي رمز المشغل",
      "auto.text.c9w5d8": "القاعدة الأساسية",
      "auto.text.ca2ut3": "فتح روابط الفريق",
      "auto.text.ca3sh7": "الخدمات المدفوعة الاختيارية",
      "auto.text.caybw0": "بند المراجعة العامة",
      "auto.text.cb7ir2": "يمكن تقديم الشكاوى من خلال إجراء معالجة الشكاوى الخاص بـ CrewPortGlobal.",
      "auto.text.ccjg5w": "باستخدام المنصة، يؤكد المرشح ما يلي:",
      "auto.text.ceni0q": "رقم تأشيرة شنغن",
      "auto.text.cf437c": "كلمة المرور",
      "auto.text.cfd5qf": "رتبة",
      "auto.text.ch3k7m": "يعني قائمة المرشحين الذين تم تحديدهم على أنهم من المحتمل أن يكونوا ذوي صلة بطلب الطاقم.",
      "auto.text.cims8x": "المرشحين المقدمين",
      "auto.text.cinc5g": "تقوم مراجعة الفريق بفحص السلطة والوثائق والموافقة على عدم الرسوم وحواجز الاستعداد.",
      "auto.text.ciomp1": "يبدأ عملك في CrewPortGlobal بالمهام.",
      "auto.text.cl30w4": "تحقق",
      "auto.text.cox5hs": "خزانة شخصية MVP",
      "auto.text.cqflm": "قدم شركتك بوضوح",
      "auto.text.crjwjo": "يجوز للمرشح تحميل مستندات مثل:",
      "auto.text.csqfn4": "رقم جواز السفر الأجنبي",
      "auto.text.cst7sd": "الموافقة والاعترافات.",
      "auto.text.ctvb7q": "استمرار الخدمة من شأنه أن يخلق مخاطر قانونية أو تنظيمية أو تتعلق بالسمعة.",
      "auto.text.cuej6q": "دورة BP-015",
      "auto.text.cy4z94": "يدعم جمع المستندات ومراجعة سير العمل؛",
      "auto.text.d3b09t": "بحار أو محترف بحري أو شخص يقوم بإنشاء ملف تعريف بحري احترافي على CrewPortGlobal.com.",
      "auto.text.d4ez6z": "الملف الشخصي المهني",
      "auto.text.d5rbjy": "يدعم مطابقة المرشحين وإعداد القائمة المختصرة؛",
      "auto.text.d6g082": "التطبيقات",
      "auto.text.d6jw5q": "خزانة الخدمة الشخصية",
      "auto.text.d6ts0m": "سلسلة هوية البحارة",
      "auto.text.d8m1m5": "معلومات مضللة عن صاحب العمل.",
      "auto.text.dckda3": "جمع المعلومات المهنية والهوية.",
      "auto.text.dd3gn8": "يتم تسجيل طلبك للمراجعة البشرية. لا تعد شركة CrewPortGlobal بالتوظيف التلقائي أو الاتصال التلقائي بصاحب العمل.",
      "auto.text.dfxbfl": "النتيجة المرجوة.",
      "auto.text.dgbtck": "تأكيد البريد الإلكتروني",
      "auto.text.djzx9c": "تخضع هذه الاتفاقية للقوانين المطبقة على شركة GTC INFORMATION TECHNOLOGY FZ-LLC في رأس الخيمة، الإمارات العربية المتحدة، ما لم يتم الاتفاق على خلاف ذلك.",
      "auto.text.dlg3gm": "طلب الطاقم الدعم",
      "auto.text.dp0bn3": "تعليقات تأييد",
      "auto.text.dpjwm3": "جي تي سي انفورميشن تكنولوجي منطقة حرة - ذ.م.م",
      "auto.text.dqyi22": "إن مخرجات الذكاء الاصطناعي هي إشارات دعم فقط ويجب ألا يتم التعامل معها على أنها قرارات توظيف تلقائية.",
      "auto.text.dsimw3": "احفظ بيانات تعريف المستند للمراجعة اليدوية دون تحميل ملفات خاصة في هذه الشريحة.",
      "auto.text.dsmuwz": "اختر نوع السفينة",
      "auto.text.dtm75x": "أصحاب السفن ومشغلي السفن ومديري السفن ومديري الطاقم وغيرهم من مستخدمي الأعمال؛",
