      "auto.text.ora30h": "mis tareas",
      "auto.text.ouyz91": "trozo",
      "auto.text.ow1nnv": "Acceso",
      "auto.text.owbgxb": "Este formulario guarda su borrador de gente de mar en el backend y conserva su ID de borrador para los siguientes pasos.",
