      "auto.text.xo6d9o": "Telepono 1",
      "auto.text.xoaiok": "Code",
      "auto.text.xpx7wp": "8. Transparency ng kandidato at mga reklamo",
      "auto.text.xrv2n": "Buksan ang workspace ng CV",
      "auto.text.xt71b": "CrewPortGlobal — Patakaran sa Pag-verify ng Pagkakakilanlan, Negosyo at Vessel | CrewPortGlobal",
      "auto.text.xxb4bo": "Pagpaparehistro ng sasakyang-dagat",
      "auto.text.xy4sn3": "Kasaysayan ng kontrata.",
      "auto.text.xz6hgv": "Maling pagkatawan ng mga kwalipikasyon o pagkakakilanlan.",
      "auto.text.xz74kx": "Katalogo ng pagreretiro",
      "auto.text.y1mzcn": "CrewPortGlobal — Seafarer Candidate Agreement | CrewPortGlobal",
      "auto.text.y1st50": "empleyado ng kumpanya",
      "auto.text.y3uti8": "Pagkilala sa onboarding",
      "auto.text.y5d9w2": "Ang mga reklamo tungkol sa recruitment, placement o mga bayarin na may kaugnayan sa trabaho ay itinuturing bilang mataas na priyoridad o kritikal na priyoridad.",
      "auto.text.y5m9bz": "Batas na namamahala at paglutas ng hindi pagkakaunawaan",
      "auto.text.y6veaa": "Panatilihing maayos ang mga dokumento",
      "auto.text.yarbbl": "Aking mga serbisyo",
      "auto.text.ybgcr8": "Protektadong read-only na diagnostic view. Walang shortlist, aplikasyon sa bakante, o visibility ng employer na nilikha dito.",
      "auto.text.ybsiew": "Nilo-load ang kasaysayan ng draft ng shortlist...",
      "auto.text.ycg0sa": "Suriin ang mga detalye ng item",
      "auto.text.ye3aoi": "Plataporma",
      "auto.text.yfs1na": "Mga talaan ng pagbabakuna kung kinakailangan.",
      "auto.text.yhx7un": "Posisyon, ranggo at uri ng sisidlan",
      "auto.text.yi56cl": "Telepono 2",
      "auto.text.ykvrhx": "Mga sertipiko, pasaporte, medikal at visa",
      "auto.text.ylzq91": "Pranses",
      "auto.text.ymak8z": "Live na detalye ng pagpapatala",
      "auto.text.yoj3ld": "Hangganan ng tiwala",
      "auto.text.yozyqa": "Ang awtoridad sa aklat ng seaman",
      "auto.text.yqjgzc": "Para sa kwalipikasyon sa panig ng supply, mga dokumento, kakayahang magamit, mga inaasahan sa kompensasyon at kahandaang tumutugma.",
      "auto.text.ytdsv7": "panghuling pagkuha, pakikipag-ugnayan, pag-deploy at mga desisyon sa pagtatrabaho;",
      "auto.text.yufv2k": "Mga kahilingan sa awtorisasyon",
      "auto.text.yvcw4g": "Ipinapakita ang compact operating cycle mula sa pagpaparehistro hanggang sa pagtutugma, ebidensya sa pagsingil at paulit-ulit na trabaho.",
      "auto.text.ywlzdb": "Nangongolekta",
      "auto.text.yxig7r": "OS",
      "auto.text.z0nqe3": "Lumalabas lang ang mga live na bakante kapag handa na ang totoong sinuri na data.",
      "auto.text.z112yh": "kung ang konteksto ng sasakyang pandagat ay magkakaugnay sa hiniling na papel, kalakalan o timeline ng pagpapatakbo.",
      "auto.text.z1qgjv": "Iwasan ang mga kontrol sa seguridad.",
      "auto.text.z3hkkp": "Ang platform ay nag-uugnay sa mga seafarer at maritime employer sa pamamagitan ng isang transparent, nabe-verify na daloy ng trabaho nang walang hindi kinakailangang burukrasya sa simula.",
      "auto.text.z3p58j": "labag sa batas na diskriminasyon;",
      "auto.text.z6arc4": "Maaaring i-refer ang mga hindi pagkakaunawaan sa mga karampatang hukuman o ibang forum na napagkasunduan sa huling legal na bersyon.",
      "auto.text.z7xtcw": "Kumpanya / ahente",
      "auto.text.z8ovdh": "Mga sertipiko.",
      "auto.text.ze6p0u": "Ang lahat ng mga estado ng kahandaan",
      "auto.text.zekpbm": "Ang konteksto ng kumpanya at sasakyang-dagat ay dapat sapat na malinaw para sa pagsusuri.",
      "auto.text.zf2dno": "Matching-ready",
      "auto.text.zgfs2p": "Bansa ng bandila",
      "auto.text.zimqla": "magmungkahi ng pagkakasunod-sunod ng kaugnayan para sa pagsusuri ng tao.",
      "auto.text.zpgawl": "Awtorisasyon ng Seafarer / Espesyalista",
      "auto.text.zqldzy": "Protektadong pag-upload ng sisidlan",
      "auto.text.zraobc": "Buksan ang Lupon ng Bakante",
      "auto.text.ztammv": "Mga marino",
      "auto.text.ztpund": "Ang mga ito ay hindi recruitment, placement o employment fees.",
      "auto.text.ztrhhb": "Nilo-load namin ang nasuri na mga detalye ng bakante mula sa CrewPortGlobal.",
      "auto.text.zugrr5": "Ipakita nang malinaw ang iyong karanasan sa pandagat, panatilihing maayos ang mga dokumento at manatiling handa para sa nasuri na mga bakante nang walang bayad sa pangangalap.",
      "auto.text.zw1h61": "AI-assisted candidate matching and ranking support;",
      "auto.text.zwekcg": "Mga nakaraang kontrata o mga rekord ng serbisyo sa dagat.",
      "auto.text.zy9lt7": "Nagparehistro ako bilang",
      "auto.text.zywohu": "Tungkulin: seafarer, may-ari ng barko, kasosyo o iba pa.",
      "auto.text.zyy465": "Pagsusuri ng pagkakumpleto",
