      "auto.text.ca3sh7": "Layanan berbayar opsional",
      "auto.text.caybw0": "Item ulasan umum",
      "auto.text.cb7ir2": "Keluhan dapat disampaikan melalui Prosedur Penanganan Keluhan CrewPortGlobal.",
      "auto.text.ccjg5w": "Dengan menggunakan Platform, Kandidat menegaskan bahwa:",
      "auto.text.ceni0q": "Nomor visa Schengen",
      "auto.text.cf437c": "Kata sandi",
      "auto.text.cfd5qf": "Pangkat",
      "auto.text.ch3k7m": "berarti daftar Kandidat yang diidentifikasi berpotensi relevan dengan Permintaan Kru.",
      "auto.text.cims8x": "Kandidat yang diajukan",
      "auto.text.cinc5g": "Tinjauan tim memeriksa otoritas, dokumen, persetujuan tanpa biaya, dan pemblokir kesiapan.",
      "auto.text.ciomp1": "Pekerjaan CrewPortGlobal Anda dimulai dengan tugas.",
      "auto.text.cl30w4": "Verifikasi",
      "auto.text.cox5hs": "MVP kabinet pribadi",
      "auto.text.cqflm": "Presentasikan perusahaan Anda dengan jelas",
