      "auto.text.csqfn4": "Nomor paspor asing",
      "auto.text.cst7sd": "Persetujuan dan pengakuan.",
      "auto.text.ctvb7q": "layanan yang berkelanjutan akan menimbulkan risiko hukum, peraturan, atau reputasi yang material.",
      "auto.text.cuej6q": "Siklus BP-015",
      "auto.text.cy4z94": "mendukung pengumpulan dokumen dan meninjau alur kerja;",
      "auto.text.d3b09t": "Pelaut, profesional maritim, atau orang yang membuat profil maritim profesional di CrewPortGlobal.com.",
      "auto.text.d4ez6z": "Profil profesional",
