      "auto.text.d6g082": "Aplikasi",
      "auto.text.d6jw5q": "Kabinet layanan pribadi",
      "auto.text.d6ts0m": "Seri ID Pelaut",
      "auto.text.d8m1m5": "Informasi perusahaan yang menyesatkan.",
      "auto.text.dckda3": "Kumpulkan informasi profesional dan identitas.",
      "auto.text.dd3gn8": "Permohonan Anda direkam untuk ditinjau manusia. CrewPortGlobal tidak menjanjikan pekerjaan otomatis atau kontak perusahaan otomatis.",
      "auto.text.dfxbfl": "Hasil yang diinginkan.",
      "auto.text.dgbtck": "Konfirmasi email",
      "auto.text.djzx9c": "Perjanjian ini diatur oleh hukum yang berlaku untuk GTC INFORMATION TECHNOLOGY FZ-LLC di Ras Al Khaimah, Uni Emirat Arab, kecuali disepakati lain.",
      "auto.text.dlg3gm": "Kru meminta dukungan",
      "auto.text.dp0bn3": "Komentar dukungan",
      "auto.text.dpjwm3": "TEKNOLOGI INFORMASI GTC FZ-LLC",
      "auto.text.dqyi22": "Keluaran AI hanya merupakan sinyal dukungan dan tidak boleh dianggap sebagai keputusan ketenagakerjaan otomatis.",
      "auto.text.dsimw3": "Simpan metadata dokumen untuk tinjauan manual tanpa mengunggah file pribadi di bagian ini.",
      "auto.text.dsmuwz": "Pilih jenis kapal",
      "auto.text.dtm75x": "pemilik kapal, operator kapal, pengelola kapal, manajer awak kapal, dan pengguna usaha lainnya;",
      "auto.text.dvi6dk": "Belum ada formulir yang dipilih. Kembali ke halaman pemilihan otorisasi.",
      "auto.text.dx7a8m": "Akses Admin",
      "auto.text.dxahtx": "Belum diperlukan",
      "auto.text.dxfsax": "CrewPortGlobal menerapkan prinsip-prinsip berikut:",
      "auto.text.dxluoy": "Pemilik kapal dapat menghentikan penggunaan platform dengan tunduk pada biaya yang belum dibayar, kewajiban kerahasiaan, tinjauan kepatuhan langsung, dan kewajiban hukum pasca-penghentian.",
      "auto.text.dyxtu8": "Pembagian ke pemberi kerja memerlukan tinjauan dan persetujuan yang terkendali.",
      "auto.text.e0gbuj": "Komunikasi dengan pemilik kapal dan mitra",
      "auto.text.e0jqcj": "Cache terjemahan mesin",
      "auto.text.e1huex": "CrewPortGlobal | Riwayat Draf Daftar Pendek",
      "auto.text.e1q76m": "Pilih setiap arah yang berlaku. Anda dapat kembali lagi ke sini nanti jika status atau aktivitas Anda berubah.",
      "auto.text.e3wggo": "KruPortGlobal",
      "auto.text.e5g751": "Tautan yang dilindungi untuk grup proyek yang disetujui",
      "auto.text.e6xlzx": "CrewPortGlobal mungkin mengandalkan informasi yang dikirimkan untuk dukungan alur kerja, persiapan daftar pendek, dan tinjauan dokumen. Klien bisnis tetap bertanggung jawab atas keakuratan, legalitas, dan ketepatan waktu informasi yang diberikan.",
      "auto.text.e6yyyl": "untuk mendukung peninjauan dokumen dan operasi alur kerja;",
      "auto.text.e8nfto": "Tertunda",
      "auto.text.eb3l9z": "Sertifikat / CoC / STCW",
      "auto.text.ebi4ca": "Permintaan harus terhubung ke pemohon dari pihak pemberi kerja yang terverifikasi.",
      "auto.text.edv1od": "Jaga peringkat, ketersediaan, dokumen, dan preferensi kapal agar siap untuk peninjauan yang sesuai.",
      "auto.text.efmneb": "Permintaan",
      "auto.text.ejjvq0": "Tidak menyerahkan dokumen milik orang lain.",
      "auto.text.emttda": "Status draf",
      "auto.text.enkx7g": "Permintaan dibandingkan dengan pasokan kandidat sebelum daftar pendek dapat dibuat.",
      "auto.text.envhyv": "tinjauan manusia diperlukan untuk keputusan sensitif.",
