      "auto.text.exvx47": "Verifikasi majikan",
      "auto.text.f22mqn": "Permintaan kru / ringkasan layanan",
      "auto.text.f3tsdr": "Izinkan penyerahan yang ditinjau oleh manusia kepada pemilik kapal atau perusahaan maritim.",
      "auto.text.f4z27e": "Sadar kesiapan dokumen",
      "auto.text.f7d5yo": "profil pelaut dan kandidat;",
      "auto.text.f7t8wj": "Daftar pendek.",
      "auto.text.fi3v9p": "Peristiwa akses terkini",
      "auto.text.fiqr4u": "Tinggi, cm",
      "auto.text.fjjbsx": "Mulai peninjauan kartu",
      "auto.text.fkhcz7": "penerimaan dan penataan permintaan kru;",
      "auto.text.fkqy0r": "Dukungan yang sesuai harus tetap relevan dengan peran dan sah secara komersial.",
      "auto.text.fl8jn8": "Formulir ini menyimpan konteks permintaan pemberi kerja, perusahaan, kapal, dan lowongan di backend.",
      "auto.text.fmpc3m": "email pengguna",
      "auto.text.fnlc51": "Alamat permanen dan registrasi",
