      "auto.text.gt408g": "Kandidat mungkin diminta untuk memberikan informasi termasuk:",
      "auto.text.gy0j5m": "Kode negara",
      "auto.text.gyxx3r": "Ulasan dan publikasi pemilik",
      "auto.text.h1id64": "Jenis rekaman",
      "auto.text.h2slv9": "Simpan formulir untuk memeriksa bidang permintaan perusahaan, kapal, dan awak bernomor sebelum peninjauan operator.",
