      "auto.text.hugqzc": "Simpan rancangan formulir pelaut",
      "auto.text.hwsuq4": "Akun dibuat",
      "auto.text.hz9oqk": "Medis",
      "auto.text.i0v4jd": "Saya menyatakan bahwa informasi dan dokumen yang saya serahkan adalah akurat dan milik saya.",
      "auto.text.i1x2a5": "Para Pihak harus mengupayakan penyelesaian dengan itikad baik sebelum proses formal.",
      "auto.text.i36sl5": "Alasan",
      "auto.text.i4a36r": "Kelayakan kandidat",
      "auto.text.i4bsm1": "11. Non-pengelakan",
      "auto.text.i4phe6": "Masa berlaku paspor asing",
      "auto.text.i6oce": "di bawah_review",
      "auto.text.i91pri": "Semua catatan",
      "auto.text.i98bib": "Bahasa kerja",
      "auto.text.ifea6k": "Tanggapi permintaan klarifikasi yang wajar.",
      "auto.text.ig2sm3": "Kewajiban kandidat",
      "auto.text.ihjyb1": "membandingkan persyaratan terstruktur dengan data yang tersedia;",
      "auto.text.ijfwtn": "Memilih formulir tidak memberikan hak peran, keanggotaan grup, visibilitas perusahaan, visibilitas kapal, publikasi kandidat, atau tindakan pihak pembeli. Seorang anggota tim harus meninjau bukti dan cakupan hubungan terlebih dahulu.",
      "auto.text.iknx5e": "Pada Tahap 1, platform diposisikan sebagai layanan teknologi dan alur kerja dan bukan sebagai agen pengawakan berlisensi kecuali persetujuan yang diperlukan telah dikonfirmasi.",
      "auto.text.ilbh2r": "Pangkat atau posisi.",
      "auto.text.ilbl94": "Cerita pendek",
