      "auto.text.j9u4ph": "Durasi kontrak.",
      "auto.text.j9u73q": "Pensiunan",
      "auto.text.jar724": "Belum",
      "auto.text.jawooh": "Kelompok gaji, tanggal bergabung dan durasi",
      "auto.text.jclysq": "Mengonfirmasi email Anda.",
      "auto.text.jcncqe": "Kirim untuk ditinjau",
      "auto.text.jg5git": "Isi data profesional",
      "auto.text.jhei6o": "Saluran kontak",
      "auto.text.ji3h2l": "Saluran kontak pilihan.",
      "auto.text.ji68zv": "Biaya dan pelaporan dilarang",
      "auto.text.jmecue": "Visa AS dikeluarkan",
      "auto.text.jo00as": "Tipe sisi pembeli",
      "auto.text.jp8i8a": "Model komersial inti adalah B2B.",
      "auto.text.jpyzz0": "Formulir profesional sisi pasokan untuk kualifikasi, dokumen, ketersediaan dan kesiapan kerja maritim.",
      "auto.text.jqy1kc": "Sertifikat bahasa",
      "auto.text.jsodqe": "Rusia",
      "auto.text.jsyo92": "CrewPortGlobal dapat mendukung organisasi dokumen dan alur kerja, namun Kandidat harus membuat keputusan sebelum menerima pekerjaan.",
      "auto.text.juqtsq": "Masa berlaku paspor",
      "auto.text.jvv0p5": "Kebangsaan",
      "auto.text.jzn8mi": "Ringkasan kandidat",
      "auto.text.k12u1x": "Pembaruan",
      "auto.text.k1oztw": "Posisi servis tahap 1",
      "auto.text.k4l7oq": "Kandidat mengakui bahwa Platform memproses data pribadi, data profesional, dan dokumen yang diunggah.",
      "auto.text.k5jjun": "4. Poin data yang digunakan dalam pencocokan",
      "auto.text.k6chh1": "berarti CrewPortGlobal.com dan sistem, database, formulir, antarmuka obrolan, alur kerja, API, dokumen, dan layanan terkait yang dioperasikan oleh GTC INFORMATION TECHNOLOGY FZ-LLC.",
      "auto.text.k6o6o9": "Tanpa Biaya Rekrutmen",
