      "auto.text.1ohjlgq": "Precisa de correção",
      "auto.text.1ohr988": "Entrando no porto.",
      "auto.text.1ohwkkz": "Informações de reclamação recomendadas",
      "auto.text.1oic8eh": "COC, endossos e prontidão STCW",
      "auto.text.1oinq74": "A verificação não garante emprego ou embarque. Ele oferece suporte a um fluxo de trabalho de correspondência mais confiável e ajuda a reduzir envios de candidatos falsos ou incompletos.",
      "auto.text.1om5ps2": "Certificados de navios-tanque químicos.",
      "auto.text.1opdpbo": "Série de livros do marinheiro",
      "auto.text.1opewba": "Qualquer suspeita de transferência de taxas, dedução indevida ou má conduta relacionada poderá resultar em revisão, suspensão ou rescisão imediata.",
      "auto.text.1opt07f": "em_revisão",
      "auto.text.1otaghm": "Escolha Função/Registro",
      "auto.text.1otg4bl": "Armazenamento de documentos.",
      "auto.text.1ovbg4b": "Motor",
      "auto.text.1ox33ze": "Etapa 3",
