      "auto.text.1p9c6v6": "9. Оновлення політики",
      "auto.text.1pa8z7n": "Номер громадянського паспорта",
      "auto.text.1padbm0": "Далі",
      "auto.text.1pak9rn": "Лист авторизації / POA",
