      "auto.text.1pq2h0q": "юридичний",
      "auto.text.1psiwul": "Продовжити реєстрацію",
      "auto.text.1puy1yi": "Зберіть морські свідоцтва та документи.",
      "auto.text.1px0cqq": "Реєстрація.",
      "auto.text.1pz5ac1": "Коли-небудь виписувався хворим?",
      "auto.text.1q2huu3": "Правила публічної видимості",
